import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model.HttpRequest
import akka.stream.Materializer

object WebhookProxyService extends App {
  implicit val system = ActorSystem("webhook-proxy")
  implicit val materializer = Materializer.matFromSystem(system)

  val route = path("api" / "v1" / "forward") {
    post {
      entity(as[String]) { userUrl =>
        Http().singleRequest(HttpRequest(uri = userUrl))
          .map(response => response.entity.dataBytes.runFold(ByteString.empty)(_ ++ _))
          .flatMap(content => Future.successful(HttpResponse(entity = content)))
      }
    }
  }
